// DataSetInspect — validate and profile an LLM fine-tuning dataset (JSONL).
//
// Training files are the least-reviewed artefact in most AI projects: they are
// generated by a script, uploaded, and only found to be wrong after a training
// run bills you. This checks the things that actually break a run, locally.

const $ = (id) => document.getElementById(id);

let rows = [];        // {line, raw, obj, error}
let report = null;

/* ── Format detection ─────────────────────────────────────────────────────── */

// Each shape below is a real, widely-used training format. Detection picks the
// one the majority of rows match, so one stray row can't misclassify the file.
const FORMATS = {
  chat: {
    label: 'Chat messages (OpenAI / fine-tuning standard)',
    test: (o) => Array.isArray(o.messages),
    textOf: (o) => (o.messages || []).map(m => `${m.role}: ${typeof m.content === 'string' ? m.content : JSON.stringify(m.content)}`).join('\n'),
  },
  prompt: {
    label: 'Prompt / completion',
    test: (o) => typeof o.prompt === 'string' && typeof o.completion === 'string',
    textOf: (o) => o.prompt + '\n' + o.completion,
  },
  alpaca: {
    label: 'Instruction / input / output (Alpaca style)',
    test: (o) => typeof o.instruction === 'string' && typeof o.output === 'string',
    textOf: (o) => [o.instruction, o.input, o.output].filter(Boolean).join('\n'),
  },
  text: {
    label: 'Raw text',
    test: (o) => typeof o.text === 'string',
    textOf: (o) => o.text,
  },
};

function detectFormat(objs) {
  const counts = {};
  for (const o of objs) {
    for (const [k, f] of Object.entries(FORMATS)) {
      if (f.test(o)) { counts[k] = (counts[k] || 0) + 1; break; }
    }
  }
  let best = null, bestN = 0;
  for (const [k, n] of Object.entries(counts)) if (n > bestN) { best = k; bestN = n; }
  return { key: best, matched: bestN, counts };
}

/* ── Token estimation ─────────────────────────────────────────────────────── */

// A real count needs the model's BPE vocabulary, which would mean shipping a
// multi-megabyte table. This is a heuristic — blending characters and words
// tracks GPT-style tokenisers to within roughly 10% on English prose, and the
// UI never presents it as exact.
function estimateTokens(text) {
  if (!text) return 0;
  const chars = text.length;
  const words = (text.match(/\S+/g) || []).length;
  return Math.max(1, Math.round((chars / 4 + words * 1.33) / 2));
}

/* ── Validation ───────────────────────────────────────────────────────────── */

function validateChat(o, issues, line) {
  const msgs = o.messages;
  if (!msgs.length) { issues.push({ line, kind: 'empty', msg: 'messages array is empty' }); return; }

  let sawAssistant = false;
  let prevRole = null;
  msgs.forEach((m, i) => {
    if (!m || typeof m !== 'object') { issues.push({ line, kind: 'shape', msg: `message ${i + 1} is not an object` }); return; }
    if (!m.role) { issues.push({ line, kind: 'shape', msg: `message ${i + 1} has no role` }); return; }
    if (!['system', 'user', 'assistant', 'tool', 'function'].includes(m.role)) {
      issues.push({ line, kind: 'role', msg: `unknown role "${m.role}" in message ${i + 1}` });
    }
    const content = typeof m.content === 'string' ? m.content : (m.content == null ? '' : JSON.stringify(m.content));
    if (!content.trim() && m.role !== 'assistant') {
      issues.push({ line, kind: 'empty', msg: `message ${i + 1} (${m.role}) has empty content` });
    }
    if (m.role === 'system' && i !== 0) issues.push({ line, kind: 'role', msg: 'system message is not first' });
    if (m.role === 'assistant') sawAssistant = true;
    if (prevRole === m.role && (m.role === 'user' || m.role === 'assistant')) {
      issues.push({ line, kind: 'role', msg: `two ${m.role} messages in a row (message ${i + 1})` });
    }
    prevRole = m.role;
  });

  // The single most common silent failure: an example with nothing for the
  // model to learn to produce.
  if (!sawAssistant) issues.push({ line, kind: 'role', msg: 'no assistant message — this example teaches nothing' });
  const last = msgs[msgs.length - 1];
  if (last && last.role !== 'assistant') issues.push({ line, kind: 'role', msg: `conversation ends with "${last.role}", not assistant` });
}

function normaliseForDupes(s) {
  return s.toLowerCase().replace(/\s+/g, ' ').replace(/[^\w ]/g, '').trim();
}

function jaccard(a, b) {
  let inter = 0;
  for (const t of a) if (b.has(t)) inter++;
  return inter / (a.size + b.size - inter || 1);
}

function analyse(text) {
  const lines = text.split('\n');
  rows = [];
  const issues = [];

  // Tolerate a JSON array as well as JSONL — people export both.
  const trimmed = text.trim();
  if (trimmed.startsWith('[')) {
    try {
      const arr = JSON.parse(trimmed);
      if (Array.isArray(arr)) {
        arr.forEach((obj, i) => rows.push({ line: i + 1, raw: JSON.stringify(obj), obj, error: null }));
      }
    } catch (e) {
      return { fatal: 'That looks like a JSON array but it does not parse: ' + e.message };
    }
  } else {
    lines.forEach((raw, i) => {
      const t = raw.trim();
      if (!t) return;
      try { rows.push({ line: i + 1, raw: t, obj: JSON.parse(t), error: null }); }
      catch (e) {
        rows.push({ line: i + 1, raw: t, obj: null, error: e.message });
        issues.push({ line: i + 1, kind: 'json', msg: 'invalid JSON on this line — ' + e.message });
      }
    });
  }

  if (!rows.length) return { fatal: 'No rows found. Expected one JSON object per line (JSONL), or a JSON array.' };

  const valid = rows.filter(r => r.obj);
  const fmt = detectFormat(valid.map(r => r.obj));
  const spec = fmt.key ? FORMATS[fmt.key] : null;

  // Rows that don't match the file's dominant shape.
  for (const r of valid) {
    if (!spec) break;
    if (!spec.test(r.obj)) issues.push({ line: r.line, kind: 'shape', msg: `row does not match the file's ${spec.label} shape` });
  }

  const texts = valid.map(r => (spec ? spec.textOf(r.obj) : JSON.stringify(r.obj)));
  const tokens = texts.map(estimateTokens);

  if (fmt.key === 'chat') {
    valid.forEach((r) => { if (Array.isArray(r.obj.messages)) validateChat(r.obj, issues, r.line); });
  }

  // Exact duplicates — O(n) via a hash of the normalised text.
  const seen = new Map();
  const exactDupes = [];
  texts.forEach((t, i) => {
    const key = normaliseForDupes(t);
    if (seen.has(key)) exactDupes.push({ line: valid[i].line, first: seen.get(key) });
    else seen.set(key, valid[i].line);
  });

  // Near duplicates — Jaccard over token sets. Comparing every pair is O(n²),
  // so rows are bucketed by length band first and only compared inside a band;
  // a near-duplicate of very different length isn't one in any useful sense.
  const nearDupes = [];
  const NEAR_LIMIT = 4000;
  let nearTruncated = false;
  if (valid.length <= NEAR_LIMIT) {
    const buckets = new Map();
    texts.forEach((t, i) => {
      const set = new Set(normaliseForDupes(t).split(' ').filter(Boolean));
      const band = Math.round(Math.log2(set.size + 1) * 2);
      if (!buckets.has(band)) buckets.set(band, []);
      buckets.get(band).push({ i, set });
    });
    for (const list of buckets.values()) {
      for (let a = 0; a < list.length; a++) {
        for (let b = a + 1; b < list.length; b++) {
          const j = jaccard(list[a].set, list[b].set);
          if (j >= 0.9 && j < 1) nearDupes.push({ line: valid[list[b].i].line, first: valid[list[a].i].line, score: j });
        }
      }
    }
  } else nearTruncated = true;

  // Label balance, when there is something that looks like a label.
  const labelCounts = new Map();
  for (const r of valid) {
    const l = r.obj.label ?? r.obj.category ?? r.obj.class ?? r.obj.intent;
    if (l != null && typeof l !== 'object') labelCounts.set(String(l), (labelCounts.get(String(l)) || 0) + 1);
  }

  const roleCounts = new Map();
  if (fmt.key === 'chat') {
    for (const r of valid) for (const m of (r.obj.messages || [])) if (m && m.role) roleCounts.set(m.role, (roleCounts.get(m.role) || 0) + 1);
  }

  return {
    fatal: null, rows, valid, issues, fmt, spec, texts, tokens,
    exactDupes, nearDupes, nearTruncated, labelCounts, roleCounts,
  };
}

/* ── Rendering ────────────────────────────────────────────────────────────── */

function histogram(values, buckets = 24) {
  if (!values.length) return '';
  const max = Math.max(...values), min = Math.min(...values);
  const span = (max - min) || 1;
  const counts = new Array(buckets).fill(0);
  for (const v of values) counts[Math.min(buckets - 1, Math.floor(((v - min) / span) * buckets))]++;
  const peak = Math.max(...counts);
  const W = 640, H = 150, bw = W / buckets;
  const bars = counts.map((c, i) => {
    const h = peak ? (c / peak) * (H - 26) : 0;
    const lo = Math.round(min + (i / buckets) * span), hi = Math.round(min + ((i + 1) / buckets) * span);
    return `<rect class="ds-bar" x="${(i * bw + 1).toFixed(1)}" y="${(H - 20 - h).toFixed(1)}" width="${(bw - 2).toFixed(1)}" height="${h.toFixed(1)}">`
      + `<title>${lo}–${hi} tokens: ${c} example${c === 1 ? '' : 's'}</title></rect>`;
  }).join('');
  return `<svg class="ds-hist" viewBox="0 0 ${W} ${H}" role="img" aria-label="Distribution of example lengths">
    ${bars}
    <line class="ds-axis" x1="0" y1="${H - 20}" x2="${W}" y2="${H - 20}" />
    <text class="ds-axis-label" x="2" y="${H - 6}">${min} tokens</text>
    <text class="ds-axis-label" x="${W - 2}" y="${H - 6}" text-anchor="end">${max} tokens</text>
  </svg>`;
}

const pct = (n, d) => (d ? ((n / d) * 100).toFixed(1) : '0.0') + '%';

function render() {
  const r = report;
  if (!r) return;
  if (r.fatal) { $('err').textContent = r.fatal; $('viewer').classList.add('ts-hidden'); return; }
  $('err').textContent = '';
  $('viewer').classList.remove('ts-hidden');

  const total = r.tokens.reduce((a, b) => a + b, 0);
  const sorted = [...r.tokens].sort((a, b) => a - b);
  const p = (q) => sorted.length ? sorted[Math.min(sorted.length - 1, Math.floor(sorted.length * q))] : 0;
  const badRows = new Set(r.issues.map(i => i.line));

  $('stats').innerHTML = [
    ['Examples', r.valid.length],
    ['With issues', badRows.size],
    ['Exact dupes', r.exactDupes.length],
    ['Near dupes', r.nearDupes.length],
    ['Est. tokens', total.toLocaleString()],
    ['Median len', p(0.5)],
  ].map(([k, v]) => `<div class="ts-stat"><span class="ts-stat-num">${escapeHtml(String(v))}</span><span class="ts-stat-label">${k}</span></div>`).join('');

  // Format banner
  const fmtLabel = r.spec ? r.spec.label : 'Unrecognised';
  const matchPct = pct(r.fmt.matched, r.valid.length);
  $('format').innerHTML = `<div class="ds-format">
      <span class="ds-format-name">${escapeHtml(fmtLabel)}</span>
      <span class="dev-muted">${matchPct} of rows match this shape</span>
    </div>`;

  // Length distribution
  $('hist').innerHTML = histogram(r.tokens);
  $('histNote').innerHTML = `p50 <strong>${p(0.5)}</strong> · p90 <strong>${p(0.9)}</strong> · p99 <strong>${p(0.99)}</strong> · longest <strong>${sorted[sorted.length - 1] || 0}</strong> tokens.
    Lengths are <em>estimates</em> — an exact count needs the model's own tokenizer vocabulary, which this page deliberately doesn't ship.`;

  // Issues
  const grouped = new Map();
  for (const i of r.issues) {
    const k = i.kind + '|' + i.msg.replace(/\d+/g, 'N');
    if (!grouped.has(k)) grouped.set(k, { kind: i.kind, msg: i.msg, lines: [] });
    grouped.get(k).lines.push(i.line);
  }
  const groups = [...grouped.values()].sort((a, b) => b.lines.length - a.lines.length);
  $('issues').innerHTML = groups.length
    ? `<table class="ts-table"><thead><tr><th>Count</th><th>Type</th><th>Problem</th><th>Lines</th></tr></thead><tbody>`
      + groups.map(g => `<tr>
          <td><strong>${g.lines.length}</strong></td>
          <td><span class="ds-kind ds-kind-${g.kind}">${g.kind}</span></td>
          <td>${escapeHtml(g.msg)}</td>
          <td class="dev-muted ds-lines">${g.lines.slice(0, 12).join(', ')}${g.lines.length > 12 ? ` … +${g.lines.length - 12}` : ''}</td>
        </tr>`).join('') + '</tbody></table>'
    : '<div class="ds-clean">✓ No structural problems found — every row parses, matches the file\'s format, and has a well-formed conversation.</div>';

  // Duplicates
  const dupRows = [
    ...r.exactDupes.map(d => ({ ...d, score: 1 })),
    ...r.nearDupes,
  ].sort((a, b) => b.score - a.score).slice(0, 40);
  $('dupes').innerHTML = dupRows.length
    ? `<table class="ts-table"><thead><tr><th>Line</th><th>Duplicate of</th><th>Similarity</th></tr></thead><tbody>`
      + dupRows.map(d => `<tr><td>${d.line}</td><td>${d.first}</td><td>${d.score === 1 ? '<strong>exact</strong>' : (d.score * 100).toFixed(0) + '%'}</td></tr>`).join('')
      + '</tbody></table>'
      + (r.nearTruncated ? '<p class="dev-muted ts-mt-sm">Near-duplicate detection was skipped: comparing every pair of more than 4,000 rows would lock up the tab. Exact duplicates above are still complete.</p>' : '')
    : '<div class="ds-clean">✓ No duplicate or near-duplicate examples.</div>';

  // Distributions
  const dist = (map, title) => {
    if (!map.size) return '';
    const entries = [...map.entries()].sort((a, b) => b[1] - a[1]);
    const max = entries[0][1];
    return `<p class="ts-card-label ts-mt-md">${title}</p>` + entries.map(([k, v]) =>
      `<div class="ds-dist-row"><span class="ds-dist-label">${escapeHtml(k)}</span>
        <span class="ds-dist-bar"><span style="width:${(v / max) * 100}%"></span></span>
        <span class="ds-dist-val">${v.toLocaleString()}</span></div>`).join('');
  };
  const balanceNote = (() => {
    if (r.labelCounts.size < 2) return '';
    const vals = [...r.labelCounts.values()];
    const ratio = Math.max(...vals) / Math.min(...vals);
    return ratio >= 3
      ? `<div class="ts-callout">Your classes are imbalanced — the most common label appears <strong>${ratio.toFixed(1)}×</strong> as often as the rarest. Expect the model to over-predict the majority class unless you rebalance or weight the loss.</div>`
      : '';
  })();
  $('dists').innerHTML = dist(r.roleCounts, 'Messages by role') + dist(r.labelCounts, 'Label balance') + balanceNote;

  // Preview
  $('preview').innerHTML = r.valid.slice(0, 8).map((row, i) => `
    <details class="ds-preview">
      <summary><span class="ds-prev-line">line ${row.line}</span> <span class="dev-muted">${r.tokens[i]} est. tokens</span> ${badRows.has(row.line) ? '<span class="ds-kind ds-kind-role">has issues</span>' : ''}</summary>
      <pre class="ds-prev-body">${escapeHtml(JSON.stringify(row.obj, null, 2).slice(0, 4000))}</pre>
    </details>`).join('');
}

/* ── Cleaned export ───────────────────────────────────────────────────────── */

$('exportBtn').addEventListener('click', () => {
  if (!report || report.fatal) return;
  const bad = new Set(report.issues.map(i => i.line));
  const dup = new Set([...report.exactDupes.map(d => d.line), ...report.nearDupes.map(d => d.line)]);
  const kept = report.valid.filter(r => !bad.has(r.line) && !dup.has(r.line));
  const out = kept.map(r => JSON.stringify(r.obj)).join('\n') + '\n';
  const url = URL.createObjectURL(new Blob([out], { type: 'application/jsonl' }));
  const a = document.createElement('a');
  a.href = url; a.download = 'dataset.clean.jsonl'; a.click();
  URL.revokeObjectURL(url);
  $('exportNote').textContent = `Exported ${kept.length.toLocaleString()} of ${report.rows.length.toLocaleString()} rows — dropped ${bad.size} with issues and ${dup.size} duplicate${dup.size === 1 ? '' : 's'}.`;
});

/* ── Input ────────────────────────────────────────────────────────────────── */

function run(text) {
  report = analyse(text);
  render();
}

let deb = null;
$('input').addEventListener('input', () => {
  clearTimeout(deb);
  deb = setTimeout(() => run($('input').value), 400);
});

$('file').addEventListener('change', (e) => {
  const f = e.target.files[0];
  if (!f) return;
  const r = new FileReader();
  r.onload = () => { $('input').value = String(r.result); run($('input').value); };
  r.readAsText(f);
});

$('sampleBtn').addEventListener('click', () => {
  // Deliberately flawed: a duplicate, a near-duplicate, a missing assistant
  // turn, two user turns in a row, an empty content field and a broken line —
  // so every check in the tool has something to find.
  const good = [
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'How do I reset my password?' }, { role: 'assistant', content: 'Open Settings → Security → Reset password, then follow the emailed link.' }] },
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'Where can I download my invoices?' }, { role: 'assistant', content: 'Billing → Invoices lists every invoice; each row has a PDF download.' }] },
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'Can I change the plan mid-month?' }, { role: 'assistant', content: 'Yes — changes take effect immediately and we prorate the difference.' }] },
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'How do I add a teammate?' }, { role: 'assistant', content: 'Team → Invite, enter their email, and pick a role.' }] },
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'How do I reset my password?' }, { role: 'assistant', content: 'Open Settings → Security → Reset password, then follow the emailed link.' }] },
    // Near-duplicate, not an exact one: punctuation alone would normalise away
    // to an identical string, so this differs by a single extra word.
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'how do I quickly reset my password!!' }, { role: 'assistant', content: 'Open Settings → Security → Reset password, then follow the emailed link.' }] },
    { messages: [{ role: 'system', content: 'You are a concise support agent.' }, { role: 'user', content: 'Do you support SSO?' }] },
    { messages: [{ role: 'user', content: 'What are your hours?' }, { role: 'user', content: 'Hello?' }, { role: 'assistant', content: 'We answer 9–5 UK time, Monday to Friday.' }] },
    { messages: [{ role: 'system', content: '' }, { role: 'user', content: 'Is there an API?' }, { role: 'assistant', content: 'Yes — see docs.example.com/api for the reference and keys.' }] },
  ];
  $('input').value = good.map(o => JSON.stringify(o)).join('\n') + '\n{"messages": [{"role": "user", "content": "truncated line...' + '\n';
  run($('input').value);
});
